1	/**
2	 * Onboarding state shape and the discriminated union of actions the reducer
3	 * accepts. The reducer is the single mutation point; every effect/component
4	 * dispatches into it. Keep this file authoritative for what the flow
5	 * remembers and how it can change.
6	 */
7	
8	import type {
9	  OnboardingStage,
10	  PersonalizationData,
11	  StagePayloads,
12	} from "../types/websocket";
13	
14	/**
15	 * Linear stage queue rendered by the page. Each stage advances forward only,
16	 * driven by either a user action (ack / confirm) or a backend "no data, skip"
17	 * signal. `getStage` walks the queue once per render — components should
18	 * never compute this themselves.
19	 */
20	export type Stage =
21	  | "questions"
22	  | "focus"
23	  | "processing"
24	  | "revealWriting"
25	  | "revealTodos"
26	  | "workflows"
27	  | "platforms"
28	  | "chat";
29	
30	export interface OnboardingState {
31	  /** Answered Q&A keyed by FIELD_NAMES (name, profession, gmail, focus). */
32	  responses: Record<string, string>;
33	  /** Index into `questions[]`; equals questions.length once Q&A is finished. */
34	  questionIndex: number;
35	  /** In-flight text input value for the active text question. */
36	  draftText: string;
37	  /** In-flight Autocomplete value for the profession question. */
38	  draftProfession: string | null;
39	
40	  /** Latest server-side personalization snapshot (REST + WS-merged). */
41	  server: PersonalizationData | null;
42	
43	  /**
44	   * Live status text from the backend, scoped per stage so a late
45	   * progress event from one stage cannot bleed into the visible label of
46	   * another. Keyed by the emitting `OnboardingStage`.
47	   */
48	  progressByStage: Partial<Record<OnboardingStage, string>>;
49	  /** Set of pipeline stages that have emitted a completion event. */
50	  completedStages: Set<OnboardingStage>;
51	
52	  /** User confirmed the writing-style reveal card. */
53	  ackedWritingStyle: boolean;
54	  /** User confirmed (or skipped) the todos reveal card. */
55	  ackedTodos: boolean;
56	
57	  /** User clicked "Understood" on the workflows reveal card. */
58	  workflowsConfirmed: boolean;
59	  /** User finished the platform-connect step — either connected or skipped. */
60	  platformsConfirmed: boolean;
61	  /** Messaging platform the user linked during the platforms stage, if any. */
62	  connectedPlatform: string | null;
63	
64	  /** Pending todo to auto-send into the chat conversation once it's ready. */
65	  todoExecutionMessage: string | null;
66	  /**
67	   * Throwaway conversation id the run-now demo streams into. Generated fresh
68	   * on every Run-Now click so the demo never bleeds into the welcome
69	   * conversation (which the user lands in after "Continue to GAIA").
70	   */
71	  todoExecutionConvoId: string | null;
72	  /**
