/**
 * `clarify` stage. Non-Gmail users answer 3 follow-up questions
 * (scope / blocker / constraint) so the todo generator has enough signal
 * to produce concrete actions. UI lives entirely in the composer footer:
 * HeroUI Tabs for navigation, RadioGroup for options, an "Other" radio
 * that reveals an Input, and a "Skip this question" radio. Submit unlocks
 * once every question has either an option, a committed custom answer,
 * or a skip.
 */

"use client";

import { Button } from "@heroui/button";
import { Input } from "@heroui/input";
import { Radio, RadioGroup } from "@heroui/radio";
import { Tab, Tabs } from "@heroui/tabs";
import { CircleArrowRight02Icon, Tick02Icon } from "@icons";
import { AnimatePresence } from "motion/react";
import * as m from "motion/react-m";
import type { Dispatch } from "react";
import { useCallback, useEffect, useMemo } from "react";
import { cn } from "@/lib/utils";
import {
  CLARIFY_MOCK_QUESTIONS,
  CLARIFY_OTHER_LABEL,
  CLARIFY_SKIP_LABEL,
} from "../../constants/clarify";
import { EASE_OUT_QUART } from "../../constants/motion";
import type { Action, OnboardingState } from "../../state/types";
import type { ClarifyAnswer, ClarifyQuestion } from "../../types";

const OPTION_VALUE_PREFIX = "opt:";
const OTHER_VALUE = "__other__";
const SKIP_VALUE = "__skip__";

interface ClarifyProps {
  state: OnboardingState;
  dispatch: Dispatch<Action>;
}

/**
 * Resolves the radio value for the active question from current state, so
 * the RadioGroup highlights the right row when re-opening the tab. When the
 * user is mid-typing an "Other" answer (draft present, no committed answer),
 * we render "Other" as the selected radio.
 */
function radioValueFor(
  question: ClarifyQuestion,
  answer: ClarifyAnswer | undefined,
  draft: string | undefined,
): string | null {
  if (answer?.kind === "option" && answer.value) {
    const idx = question.options.indexOf(answer.value);
    return idx >= 0 ? `${OPTION_VALUE_PREFIX}${idx}` : null;
  }
  if (answer?.kind === "custom" && answer.value) return OTHER_VALUE;
  if (answer?.kind === "skip") return SKIP_VALUE;
  if (draft && draft.length > 0) return OTHER_VALUE;
  return null;
}

function isQuestionAnswered(
  answer: ClarifyAnswer | undefined,
  draft: string | undefined,
): boolean {
  if (!answer) return !!draft?.trim();
  if (answer.kind === "skip") return true;
  if (answer.kind === "option") return !!answer.value;
  if (answer.kind === "custom") return !!answer.value?.trim();
  return false;
}

/**
 * Stage content region. Intentionally empty — the entire clarify experience
 * lives in the composer so it sits next to the existing CTA chrome and
 * doesn't push the transcript around.
 */
export function Clarify(_props: ClarifyProps) {
  return null;
}

export function ClarifyComposer({ state, dispatch }: ClarifyProps) {
  // Until the backend endpoint lands we seed the mock set on first mount so
  // the UX is reviewable end-to-end. Once `clarifyQuestions` is non-null the
  // load action becomes idempotent.
  useEffect(() => {
    if (state.clarifyQuestions != null) return;
    dispatch({ type: "clarifyLoaded", questions: CLARIFY_MOCK_QUESTIONS });
  }, [state.clarifyQuestions, dispatch]);

  const questions = state.clarifyQuestions ?? [];
  const activeId = state.clarifyActiveTab ?? questions[0]?.id ?? "";
  const activeQuestion = useMemo(
    () => questions.find((q) => q.id === activeId) ?? questions[0],
    [questions, activeId],
  );

  const allAnswered = useMemo(
    () =>
      questions.length > 0 &&
      questions.every((q) =>
        isQuestionAnswered(
          state.clarifyAnswers[q.id],
          state.clarifyCustomDrafts[q.id],
        ),
      ),
    [questions, state.clarifyAnswers, state.clarifyCustomDrafts],
  );

  const handleRadioChange = useCallback(
    (value: string) => {
      if (!activeQuestion) return;
      if (value === SKIP_VALUE) {
        dispatch({ type: "clarifySkip", questionId: activeQuestion.id });
        return;
      }
      if (value === OTHER_VALUE) {
        // Selecting "Other" but not typing anything yet — clear the answer
        // so the question stays incomplete until the user types something.
        dispatch({
          type: "clarifyCustomDraft",
          questionId: activeQuestion.id,
          value: state.clarifyCustomDrafts[activeQuestion.id] ?? "",
        });
        return;
      }
      if (value.startsWith(OPTION_VALUE_PREFIX)) {
        const idx = Number(value.slice(OPTION_VALUE_PREFIX.length));
        const option = activeQuestion.options[idx];
        if (option) {
          dispatch({
            type: "clarifySelectOption",
            questionId: activeQuestion.id,
            value: option,
          });
        }
      }
    },
    [activeQuestion, dispatch, state.clarifyCustomDrafts],
  );

  const handleCustomChange = useCallback(
    (value: string) => {
      if (!activeQuestion) return;
      dispatch({
        type: "clarifyCustomDraft",
        questionId: activeQuestion.id,
        value,
      });
    },
    [activeQuestion, dispatch],
  );

  const handleCustomCommit = useCallback(() => {
    if (!activeQuestion) return;
    dispatch({ type: "clarifyCustomCommit", questionId: activeQuestion.id });
  }, [activeQuestion, dispatch]);

  const handleSubmit = useCallback(() => {
    // Commit any pending "Other" drafts before locking in the submission so
    // the transcript reflects what the user actually typed.
    for (const q of questions) {
      if (
        !state.clarifyAnswers[q.id] &&
        state.clarifyCustomDrafts[q.id]?.trim()
      ) {
        dispatch({ type: "clarifyCustomCommit", questionId: q.id });
      }
    }
    dispatch({ type: "clarifySubmit" });
  }, [questions, state.clarifyAnswers, state.clarifyCustomDrafts, dispatch]);

  if (!activeQuestion) return null;

  const activeAnswer = state.clarifyAnswers[activeQuestion.id];
  const activeDraft = state.clarifyCustomDrafts[activeQuestion.id] ?? "";
  const selectedValue = radioValueFor(activeQuestion, activeAnswer, activeDraft);
  const isOtherSelected = selectedValue === OTHER_VALUE;

  return (
    <m.div
      initial={{ opacity: 0, y: 12 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.4, ease: EASE_OUT_QUART }}
      className="mx-2 rounded-2xl bg-zinc-800 p-4"
    >
      <div className="mb-3 flex items-center justify-between">
        <Tabs
          aria-label="Clarify questions"
          selectedKey={activeId}
          onSelectionChange={(key) =>
            dispatch({ type: "clarifyTab", questionId: String(key) })
          }
          size="sm"
          variant="solid"
          radius="full"
          classNames={{
            tabList: "bg-zinc-900",
          }}
        >
          {questions.map((q, idx) => {
            const answered = isQuestionAnswered(
              state.clarifyAnswers[q.id],
              state.clarifyCustomDrafts[q.id],
            );
            return (
              <Tab
                key={q.id}
                title={
                  <span className="flex items-center gap-1.5">
                    <span>Q{idx + 1}</span>
                    {answered && (
                      <Tick02Icon className="size-3 text-emerald-400" />
                    )}
                  </span>
                }
              />
            );
          })}
        </Tabs>
        <span className="text-xs text-zinc-500">
          {
            Object.keys(state.clarifyAnswers).filter((id) =>
              isQuestionAnswered(
                state.clarifyAnswers[id],
                state.clarifyCustomDrafts[id],
              ),
            ).length
          }{" "}
          / {questions.length}
        </span>
      </div>

      <div className="rounded-2xl bg-zinc-900 p-3">
        <p className="mb-3 text-sm text-zinc-100">{activeQuestion.question}</p>

        <RadioGroup
          value={selectedValue ?? ""}
          onValueChange={handleRadioChange}
          classNames={{ wrapper: "gap-1.5" }}
        >
          {activeQuestion.options.map((option, idx) => (
            <Radio
              key={`${OPTION_VALUE_PREFIX}${idx}`}
              value={`${OPTION_VALUE_PREFIX}${idx}`}
              classNames={{
                base: cn(
                  "m-0 max-w-none rounded-xl border-0 bg-zinc-800/60 p-2",
                  "data-[selected=true]:bg-zinc-800",
                ),
                label: "text-sm text-zinc-200",
              }}
            >
              {option}
            </Radio>
          ))}
          <Radio
            value={OTHER_VALUE}
            classNames={{
              base: cn(
                "m-0 max-w-none rounded-xl border-0 bg-zinc-800/60 p-2",
                "data-[selected=true]:bg-zinc-800",
              ),
              label: "text-sm text-zinc-200",
            }}
          >
            {CLARIFY_OTHER_LABEL}
          </Radio>
          <Radio
            value={SKIP_VALUE}
            classNames={{
              base: cn(
                "m-0 max-w-none rounded-xl border-0 bg-zinc-800/60 p-2",
                "data-[selected=true]:bg-zinc-800",
              ),
              label: "text-sm text-zinc-400",
            }}
          >
            {CLARIFY_SKIP_LABEL}
          </Radio>
        </RadioGroup>

        <AnimatePresence initial={false}>
          {isOtherSelected && (
            <m.div
              initial={{ opacity: 0, height: 0, marginTop: 0 }}
              animate={{ opacity: 1, height: "auto", marginTop: 10 }}
              exit={{ opacity: 0, height: 0, marginTop: 0 }}
              transition={{ duration: 0.25, ease: EASE_OUT_QUART }}
              className="overflow-hidden"
            >
              <Input
                autoFocus
                size="sm"
                value={activeDraft}
                onValueChange={handleCustomChange}
                onBlur={handleCustomCommit}
                placeholder="Type your answer..."
                classNames={{ inputWrapper: "bg-zinc-800" }}
              />
            </m.div>
          )}
        </AnimatePresence>
      </div>

      <div className="mt-3 flex justify-end">
        <Button
          color="primary"
          radius="full"
          size="sm"
          isDisabled={!allAnswered}
          onPress={handleSubmit}
          endContent={<CircleArrowRight02Icon className="size-4" />}
        >
          Submit & continue
        </Button>
      </div>
    </m.div>
  );
}

