):
    """Complete user onboarding by storing preferences and queuing the intelligence pipeline."""
    log.set(
        user={"id": user["user_id"]},
        onboarding={
            "operation": "complete",
            "is_complete": True,
            "timezone": tz_info[0],
        },
    )

    try:
        updated_user = await complete_onboarding(
            user["user_id"],
            onboarding_data,
