  // Local reducer so the demo runs against the real state machine. `useEffect`
  // inside ClarifyComposer auto-seeds the mocked 3 questions, so we don't have
  // to dispatch anything ahead of mount.
  const [state, dispatch] = useReducer(reducer, initialState);

