1	/**
2	 * `clarify` stage. Non-Gmail users answer 3 follow-up questions
3	 * (scope / blocker / constraint) so the todo generator has enough signal
4	 * to produce concrete actions. UI lives entirely in the composer footer:
5	 * HeroUI Tabs for navigation, RadioGroup for options, an "Other" radio
6	 * that reveals an Input, and a "Skip this question" radio. Submit unlocks
7	 * once every question has either an option, a committed custom answer,
8	 * or a skip.
9	 */
10	
11	"use client";
12	
13	import { Button } from "@heroui/button";
14	import { Input } from "@heroui/input";
15	import { Radio, RadioGroup } from "@heroui/radio";
16	import { Skeleton } from "@heroui/skeleton";
17	import { Tab, Tabs } from "@heroui/tabs";
18	import { CircleArrowRight02Icon, Tick02Icon } from "@icons";
19	import { AnimatePresence } from "motion/react";
20	import * as m from "motion/react-m";
21	import type { Dispatch } from "react";
22	import { useCallback, useMemo } from "react";
23	import { cn } from "@/lib/utils";
24	import {
25	  CLARIFY_OTHER_LABEL,
26	  CLARIFY_SKIP_LABEL,
27	} from "../../constants/clarify";
28	import { EASE_OUT_QUART } from "../../constants/motion";
29	import type { Action, OnboardingState } from "../../state/types";
30	import type { ClarifyAnswer, ClarifyQuestion } from "../../types";
31	
32	const OPTION_VALUE_PREFIX = "opt:";
33	const OTHER_VALUE = "__other__";
34	const SKIP_VALUE = "__skip__";
35	
36	interface ClarifyProps {
37	  state: OnboardingState;
38	  dispatch: Dispatch<Action>;
39	}
40	
41	/**
42	 * Resolves the radio value for the active question from current state, so
43	 * the RadioGroup highlights the right row when re-opening the tab. When the
44	 * user is mid-typing an "Other" answer (draft present, no committed answer),
45	 * we render "Other" as the selected radio.
46	 */
47	function radioValueFor(
48	  question: ClarifyQuestion,
49	  answer: ClarifyAnswer | undefined,
50	  draft: string | undefined,
51	): string | null {
52	  if (answer?.kind === "option" && answer.value) {
53	    const idx = question.options.indexOf(answer.value);
54	    return idx >= 0 ? `${OPTION_VALUE_PREFIX}${idx}` : null;
55	  }
56	  if (answer?.kind === "custom" && answer.value) return OTHER_VALUE;
57	  if (answer?.kind === "skip") return SKIP_VALUE;
58	  if (draft && draft.length > 0) return OTHER_VALUE;
59	  return null;
60	}
61	
62	function isQuestionAnswered(
63	  answer: ClarifyAnswer | undefined,
64	  draft: string | undefined,
65	): boolean {
66	  if (!answer) return !!draft?.trim();
67	  if (answer.kind === "skip") return true;
68	  if (answer.kind === "option") return !!answer.value;
69	  if (answer.kind === "custom") return !!answer.value?.trim();
70	  return false;
71	}
72	
73	export function ClarifyComposer({ state, dispatch }: ClarifyProps) {
74	  const questions = state.clarifyQuestions ?? [];
75	  const activeId = state.clarifyActiveTab ?? questions[0]?.id ?? "";
76	  const activeQuestion = useMemo(
77	    () => questions.find((q) => q.id === activeId) ?? questions[0],
78	    [questions, activeId],
79	  );
80	
81	  const allAnswered = useMemo(
82	    () =>
83	      questions.length > 0 &&
84	      questions.every((q) =>
85	        isQuestionAnswered(
86	          state.clarifyAnswers[q.id],
87	          state.clarifyCustomDrafts[q.id],
88	        ),
89	      ),
90	    [questions, state.clarifyAnswers, state.clarifyCustomDrafts],
91	  );
92	
93	  const handleRadioChange = useCallback(
