1	/**
2	 * Builds the chat-style transcript shown above the composer during the Q&A
3	 * and processing stages. Pure; derives entirely from `responses` and
4	 * `questionIndex` so it can be memoised cheaply.
5	 */
6	
7	import { FIELD_NAMES, professionOptions, questions } from "../constants";
8	import {
9	  CLARIFY_INTRO,
10	  CLARIFY_PROCESSING_MSG,
11	  CLARIFY_SKIP_LABEL,
12	} from "../constants/clarify";
13	import {
14	  FOCUS_QUESTION,
15	  PROCESSING_MSG_FOCUS,
16	  PROCESSING_MSG_GMAIL,
17	  PROCESSING_MSG_NO_GMAIL,
18	} from "../constants/messages";
19	import type { Message } from "../types";
20	import type { OnboardingState } from "./types";
21	
22	/**
23	 * Derive the chat-style transcript shown above the input from `responses`
24	 * + `questionIndex`. Pure function, no side effects.
25	 *
26	 * The bot's first follow-up message uses the user's first name as a greeting
27	 * — that's the only dynamic part. Everything else is a fixed string keyed off
28	 * the field name.
29	 */
30	export function getMessages(state: OnboardingState): Message[] {
31	  const messages: Message[] = [];
32	  const { responses, questionIndex } = state;
33	
34	  for (let i = 0; i < Math.min(questionIndex + 1, questions.length); i++) {
35	    const q = questions[i];
36	
37	    let botContent = q.question;
38	    if (i === 1 && responses[FIELD_NAMES.NAME]) {
39	      const firstName = responses[FIELD_NAMES.NAME].split(" ")[0];
40	      botContent = `Nice to meet you, ${firstName}!<NEW_MESSAGE_BREAK>${q.question}`;
41	    }
42	
43	    messages.push({
44	      id: q.id,
45	      type: "bot",
46	      content: botContent,
47	    });
48	
49	    const answer = responses[q.fieldName];
50	    if (answer != null) {
51	      messages.push({
52	        id: `user-${q.id}`,
53	        type: "user",
54	        content: displayValue(q.fieldName, answer),
55	        questionFieldName: q.fieldName,
56	      });
57	    }
58	  }
59	
60	  // Past last question — show focus prompt or processing message
61	  if (questionIndex >= questions.length) {
62	    const gmail = responses[FIELD_NAMES.GMAIL];
63	    const focus = responses[FIELD_NAMES.FOCUS];
64	
65	    if (gmail === "skipped" && focus == null) {
66	      messages.push({
67	        id: "focus-q",
68	        type: "bot",
69	        content: FOCUS_QUESTION,
70	      });
71	    } else if (focus != null) {
72	      // No-Gmail path: render the synthetic focus prompt before the user's
